/* -------------------------------------------------------------------------------------------
 * The full MealBonusesS accumulator, VERBATIM, all 3 arms bonuses/meals.mjs flags as unread.
 * MealBonusesS builder (N.js:6212-6214, `p._customBlock_?` — the per-tick accumulator loop):
 *   for each meal g (0..73) with a level > 0:
 *     MealBonusesS[MealINFO[g][5]] +=
 *       BonusMultiCook(g)                                  // ARM 1 — cooking-mastery, per meal
 *       * CookingR("CookingMealBonusMultioo", 0, 0)         // ARM 2 — global meal multiplier
 *       * Summoning("RibbonBonus", Ribbon[28+g], 0)          // ARM 3 — per-meal ribbon rank
 *       * Meals[0][g]                                        // the meal's LEVEL
 *       * MealINFO[g][2]                                     // the flat per-level coeff (MEAL_INFO[g].coeff above)
 *
 * (bonuses/meals.mjs's mealBonus() currently only implements `lv * coeff` — a documented LOWER
 * BOUND. All 3 arms below multiply that lower bound; each is >= 1 for a leveled meal, so the true
 * value is always >= the current implementation's output.)
 *
 * ARM 1 — BonusMultiCook(mealIdx): the per-meal Cooking Mastery ("yellow points") diminishing
 * bonus. N.js:18136-18137 (`m._customBlock_Summoning2`, owner fn literally named "Summoning2" —
 * cooking mastery hides here, not in a cooking-named dispatcher):
 *   if("BonusMultiCook"==d) return
 *     1 + 100*CookMaster[0][mealIdx] / (CookMaster[0][mealIdx]+5) / 100;
 *   // CookMaster[0][mealIdx] = "yellow points" spent leveling up mastery FOR THIS SPECIFIC MEAL
 *   // (spent by clicking individual meals in the Cooking Mastery UI, N.js:15600:
 *   //    CookMaster[0][mealIdx]++).
 *   // Diminishing-return curve: 1 pt -> 1.0167x, 10 pts -> 1.0667x, 100 pts -> 1.0952x,
 *   // asymptotically approaches 2.0x as points -> infinity. NEVER exceeds 2x.
 *
 * ARM 2 — CookingMealBonusMultioo: the GLOBAL meal multiplier (applies equally to every meal).
 * N.js:12400-12401 (`p._customBlock_CookingR`):
 *   if("CookingMealBonusMultioo"==d) return
 *     (1 + (MainframeBonus(116) + Breeding("ShinyBonusS","Nah",20,-1)) / 100)
 *     * (1 + Summoning("WinBonus",26,0) / 100)
 *     * (1 + 25*Companions(162) / 100);
 *   // 3 sub-terms, none expanded further here (separate dispatchers, generic across the game):
 *   //   MainframeBonus(116)                 — Lab mainframe node 116's bonus value
 *   //   Breeding("ShinyBonusS","Nah",20,-1) — shiny-pet bonus id 20 (SHINY_BONUS_NAMES[20] in
 *   //                                          gamedata.mjs = "+{%_Bonuses_from_All_Meals" —
 *   //                                          confirms this IS the meal-multi shiny bonus)
 *   //   Summoning("WinBonus",26,0)          — sailing captain win-bonus slot 26
 *   //   Companions(162)                     — companion id 162, +25% flat per point owned
 *
 * ARM 3 — RibbonBonus(ribbonLv): the per-meal RIBBON rank bonus. Called as
 * `Summoning("RibbonBonus", Ribbon[28+g], 0)` — Ribbon[] is padded so slots 28..28+73 map 1:1 to
 * meal indices 0..73 (confirmed at N.js:9438: `for(;Ribbon.length-28<MealINFO.length;)Ribbon.push(0)`).
 * N.js:18037 (`m._customBlock_Summoning`):
 *   if("RibbonBonus"==d) return 1 + (
 *       Math.floor(5*b + Math.floor(b/2)*(4+6.5*Math.floor(b/5)))
 *       + ( Math.floor(b/4) * (GetSetBonus("EMPEROR_SET","Bonus",0,0)/4)
 *           + Math.floor(b/10) * Dreamstuff("CloudBonus",73) )
 *     ) / 100;
 *   // b = ribbon level 0..RIBBONS_MAX_LV for that meal slot. GetSetBonus("EMPEROR_SET",...) and
 *   // Dreamstuff("CloudBonus",73) (an Equinox/"Dream" cloud upgrade — the client calls Equinox
 *   // content "Dream" internally) are further dispatchers, not expanded here.
 *   // RIBBONS_MAX_LV = 25 (RibbonsMaxLV constant, same statement as MEAL_LEVEL_CAP below).
 * ------------------------------------------------------------------------------------------- */

/** RibbonsMaxLV — flat constant, N.js:12415 (same statement as CookingMealMaxLVlol). */
export const RIBBON_MAX_LV = 25;

/* -------------------------------------------------------------------------------------------
 * Meal level-up COST formula — CookingMenuMealCosts(mealIdx), N.js:12412-12415
 * (`p._customBlock_CookingR`). Cost is paid from Meals[2][mealIdx] (accumulated spice/points);
 * leveling deducts this from Meals[2] and increments Meals[0] (N.js:15602).
 *
 *   CookingMenuMealCosts(b) =
 *     Math.max(.001, 1 / Math.max(1, 5*Companions(162)))
 *     * Math.pow(10, 22*Math.floor((Meals[0][b]+1000)/1111))
 *     * (1 / Math.min(5, Math.max(1, 1+10*AchieveStatus(233)/100)))
 *     * Math.max(.001, Math.pow(
 *         Math.max(.58, .8 - .22*Dreamstuff("CloudBonus",33)),
 *         Math.min(OptionsListAccount[193], Dream[11])
 *       ))
 *     * (10 + (Meals[0][b] + Math.pow(Meals[0][b], 2)))
 *     * Math.pow(1.2 + .05*Meals[0][b], Meals[0][b])
 *     * Math.pow(1 + .4*Math.floor((Meals[0][b]+1000)/1111), Meals[0][b]);
 *
 * where Meals[0][b] = the meal's CURRENT level (pre-level-up). Confirms the previously-suspected
 * pow(1.2+0.05*L, L) shape, plus:
 *   - a "(10 + L + L^2)" base multiplier
 *   - a Companions(162) discount (same companion that gives the ARM-1 global +25% above — dual use)
 *   - an AchieveStatus(233) discount (up to 5x cheaper)
 *   - a Dreamstuff("CloudBonus",33) discount, base range .58-.8, exponentiated by
 *     min(OptionsListAccount[193], Dream[11]) — an Equinox/"Dream" cloud upgrade (id 33) whose
 *     effective exponent is capped by BOTH an account option counter and Dream[11] (a raw save
 *     value, not further expanded here)
 *   - a "soft reset" scaling that jumps 10^22 and applies an extra ^L multiplier every 1111
 *     levels (`Math.floor((L+1000)/1111)`)
 * Cross-checked term-for-term against idleon-toolbox/parsers/world-4/cooking.ts:749-766
 * (`getMealLevelCost`) — 0 discrepancies, same magic constants throughout.
 * -------------------------------------------------------------------------------------------
 *
 * Meal level CAP — CookingMealMaxLVlol, N.js:12415 (`p._customBlock_CookingR`, same statement
 * block as RibbonsMaxLV):
 *
 *   CookingMealMaxLVlol() = Math.round(30
 *     + Sailing("ArtifactBonus",17,0)                              // Causticolumn artifact
 *     + 10*Ninja("EmporiumBonus",20,0)                              // Jade Emporium item #1
 *     + 10*Ninja("EmporiumBonus",21,0)                              // Jade Emporium item #2
 *     + 30*Spelunk("DoWeHaveLoreN1",5,0)                            // lore boss #5 defeated
 *     + Math.min(20, Summoning("GrimoireUpgBonus",26,0))            // Grimoire upgrade #26, capped
 *   );
 *
 * All 5 sources from the research brief confirmed present. See MEAL_LEVEL_CAP_SOURCES below for
 * the resolved identities/values. Cross-checked against idleon-toolbox's `getMealMaxLevel()`
 * (cooking.ts:735-748) — 0 discrepancies, including the exact +20 cap on the Grimoire term.
 * ------------------------------------------------------------------------------------------- */

/** Meal level cap = 30 (base) + sum of these sources. Each `cap` is the max this source can add;
 *  `Sailing("ArtifactBonus",17,0)` (Causticolumn) is NOT flat-capped in the client — its value is
 *  whatever the artifact's own bonus formula returns at max artifact level (not looked up here;
 *  see gamedata-w3-* / bonuses/sailing.mjs's ArtifactBonus table if one exists for artifact 17). */
export const MEAL_LEVEL_CAP_SOURCES = {
  base: 30,
  causticolumnArtifact: { dispatcher: 'Sailing("ArtifactBonus",17,0)', note: "Causticolumn artifact — na.ArtifactInfo() row 17 (N.js:23870); value = artifact's own level-scaled bonus, not flat" },
  jadeEmporium20: { dispatcher: 'Ninja("EmporiumBonus",20,0)', cap: 10, note: "Jade Emporium purchase #20 (toolbox: Papa_Blob's_Quality_Guarantee) — +10 flat if unlocked" },
  jadeEmporium21: { dispatcher: 'Ninja("EmporiumBonus",21,0)', cap: 10, note: "Jade Emporium purchase #21 (toolbox: Chef_Geustloaf's_Cutting_Edge_Philosophy) — +10 flat if unlocked" },
  loreBoss5: { dispatcher: 'Spelunk("DoWeHaveLoreN1",5,0)', cap: 30, note: "lore boss #5 defeated — +30 flat" },
  grimoire26: { dispatcher: 'Summoning("GrimoireUpgBonus",26,0)', cap: 20, note: "Grimoire upgrade #26, capped at +20 via Math.min(20, ...)" },
};

